const getAllItems = (sourceDB) => {
  const src = (sourceDB && Object.keys(sourceDB).length > 0) ? sourceDB : DB;
  return Object.entries(src).flatMap(([cat, items]) => items.map(i => ({...i, category: cat})));
};

const getHighlights = (sourceDB) => getAllItems(sourceDB).filter(i => i.highlight);

const getCatColor = (catId) => {
  const c = CATEGORIES.find(x => x.id === catId);
  return c ? c.color : RED;
};


// ── Hauptkomponente ─────────────────────────────────────────────
export default function App() {
  const [tab,      setTab]      = useState('home');
  const [cat,      setCat]      = useState('all');
  const [query,    setQuery]    = useState('');
  const [saved,    setSaved]    = useState([]);
  const [weather,  setWeather]  = useState(null);
  const [detail,   setDetail]   = useState(null);
  const [calMonth, setCalMonth] = useState(new Date(2026, 2, 1));
  const [calCat,   setCalCat]   = useState('all');
  const [subFilter, setSubFilter] = useState('all');

  // Live-Daten aus Supabase laden
  const [liveListings, setLiveListings] = useState([]);
  const [liveEvents,   setLiveEvents]   = useState([]);
  const [dataSource,   setDataSource]   = useState('lokal'); // lokal | supabase

  useEffect(() => {
    // Listings laden
    sbFetch('listings', 'is_active=eq.true&order=category,name&limit=500').then(data => {
      if (data && data.length > 0) {
        // Supabase-Format in App-Format umwandeln
        const mapped = {};
        data.forEach(item => {
          if (!mapped[item.category]) mapped[item.category] = [];
          mapped[item.category].push({
            id:       item.id,
            name:     item.name,
            address:  item.address || '',
            hours:    item.hours || '',
            cuisine:  item.sub_type || '',
            phone:    item.phone || '',
            website:  item.website || '',
            stars:    item.stars || '',
            desc:     item.description || '',
            highlight: item.is_premium || false,
            highlight: item.is_premium || false,
          });
        });
        setLiveListings(mapped);
        setDataSource('supabase');
        console.log('✅ Live-Daten geladen:', data.length, 'Einträge');
      }
    });

    // Events laden
    sbFetch('events', 'is_active=eq.true&order=event_date&limit=100').then(data => {
      if (data && data.length > 0) {
        const mapped = data.map(e => ({
          id:       e.id,
          date:     e.event_date,
          title:    e.title,
          cat:      e.cat,
          location: e.location || '',
          time:     e.event_time || '',
          price:    e.price || '',
          desc:     e.description || '',
        }));
        setLiveEvents(mapped);
      }
    });
  }, []);

  // Wetter laden
  useEffect(() => {
    fetch('https://api.open-meteo.com/v1/forecast?latitude=47.4988&longitude=8.7269&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m&timezone=Europe/Zurich')
      .then(r => r.json())
      .then(d => {
        const c = d.current;
        const icons = {0:'☀️',1:'🌤️',2:'⛅',3:'☁️',45:'🌫️',61:'🌧️',71:'🌨️',80:'🌦️',95:'⛈️'};
        const descs = {0:'Sonnig',1:'Meist sonnig',2:'Teilweise bewölkt',3:'Bewölkt',61:'Regen',71:'Schnee',80:'Schauer',95:'Gewitter'};
        setWeather({
          temp: Math.round(c.temperature_2m),
          humidity: c.relative_humidity_2m,
          wind: Math.round(c.wind_speed_10m),
          icon: icons[c.weather_code] || '🌡️',
          desc: descs[c.weather_code] || '–',
        });
      }).catch(() => {});
  }, []);

  const toggleSave = id => setSaved(p => p.includes(id) ? p.filter(s => s !== id) : [...p, id]);
  const scrollRef = useRef(null);

  // Scroll to results when category or subfilter changes
  useEffect(() => {
    if (scrollRef.current && cat !== 'all') {
      setTimeout(() => {
        scrollRef.current?.scrollTo({ y: 420, animated: true });
      }, 100);
    }
  }, [cat, subFilter]);

  const activeDB = (liveListings && Object.keys(liveListings).length > 0) ? liveListings : DB;
  const items = cat === 'all' ? getAllItems(liveListings) : (activeDB[cat] || []).map(i => ({...i, category: cat}));
  const subFiltered = cat === 'all' ? items : items.filter(i => {
    if (subFilter === 'all') return true;
    const sf = (SUBFILTERS[cat] || []).find(f => f.id === subFilter);
    if (!sf || !sf.match) return true;
    return sf.match((i.cuisine || '').toLowerCase(), i);
  });

  const filtered = subFiltered.filter(i =>
    !query ||
    i.name.toLowerCase().includes(query.toLowerCase()) ||
    (i.address || '').toLowerCase().includes(query.toLowerCase()) ||
    (i.cuisine || '').toLowerCase().includes(query.toLowerCase())
  );

  // ── Tab: Home ─────────────────────────────────────────────────
  const HomeTab = () => (
    <ScrollView 
        ref={scrollRef}
        style={sty.scroll} 
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
        maintainVisibleContentPosition={{minIndexForVisible: 0}}>
      {/* Hero */}
      <View style={sty.hero}>
        <View style={sty.heroRow}>
          <Image source={{uri: WAPPEN}} style={sty.wappen} resizeMode="contain"/>
          <View style={{flex:1}}>
            <Text style={sty.heroSup}>Willkommen in</Text>
            <Text style={sty.heroTitle}>Winterthur</Text>
          </View>
          {weather && (
            <View style={sty.weatherPill}>
              <Text style={{fontSize:16}}>{weather.icon}</Text>
              <Text style={sty.weatherTemp}>{weather.temp}°C</Text>
            </View>
          )}
        </View>
        {weather && (
          <Text style={sty.weatherSub}>
            {weather.desc} · 💧{weather.humidity}% · 💨{weather.wind}km/h
          </Text>
        )}
      </View>

      {/* Quick Actions */}
      <View style={sty.quickRow}>
        {[
          {icon:'🎫',label:'Winti Pass',  color:'#B00000'},
          {icon:'🚆',label:'ÖV-Tickets', color:'#1A5276'},
          {icon:'🗺️',label:'Karte',       color:'#0E6655', onPress:()=>setTab('map')},
          {icon:'📅',label:'Events',      color:'#6C3483', onPress:()=>setTab('calendar')},
        ].map(a => (
          <TouchableOpacity key={a.label} style={sty.quickBtn} onPress={a.onPress}>
            <View style={[sty.quickIcon, {backgroundColor: a.color}]}>
              <Text style={{fontSize:22}}>{a.icon}</Text>
            </View>
            <Text style={sty.quickLabel}>{a.label}</Text>
          </TouchableOpacity>
        ))}
      </View>

      {/* Winti Pass Banner */}
      <View style={sty.passBanner}>
        <View style={{flex:1}}>
          <Text style={sty.passTitle}>🎫 Winti Pass</Text>
          <Text style={sty.passSub}>Museen + ÖV · 1 Tag CHF 35 · 3 Tage CHF 55</Text>
        </View>
        <TouchableOpacity style={sty.passBtn}>
          <Text style={sty.passBtnTxt}>Mehr</Text>
        </TouchableOpacity>
      </View>

      {/* Highlights */}
      <View style={sty.sectionHeader}>
        <Text style={sty.sectionTitle}>✨ Highlights</Text>
        <Text style={sty.sectionSub}>{getHighlights({}).length} Top-Picks</Text>
      </View>
      <ScrollView horizontal showsHorizontalScrollIndicator={false}
        contentContainerStyle={{paddingLeft:16, paddingBottom:14, gap:10}}>
        {getHighlights({}).map(item => {
          const bg = CAT_COLORS[item.category] || RED;
          return (
            <TouchableOpacity key={item.id} style={sty.hlCard} onPress={()=>setDetail(item)}>
              <View style={[sty.hlImg, {backgroundColor: bg}]}>
                <Text style={{fontSize:32}}>{CAT_ICONS[item.category]}</Text>
              </View>
              <View style={sty.hlBody}>
                <Text style={sty.hlName} numberOfLines={2}>{item.name}</Text>
                <Text style={sty.hlAddr} numberOfLines={1}>{item.address}</Text>
              </View>
            </TouchableOpacity>
          );
        })}
      </ScrollView>

      {/* Nächste Events */}
      <View style={sty.sectionHeader}>
        <Text style={sty.sectionTitle}>📅 Nächste Events</Text>
        <TouchableOpacity onPress={()=>setTab('calendar')}>
          <Text style={sty.sectionLink}>Alle →</Text>
        </TouchableOpacity>
      </View>
      {EVENTS.slice(0,3).map(ev => (
        <View key={ev.id} style={sty.evtRow}>
          <View style={[sty.evtDate, {backgroundColor: RED}]}>
            <Text style={sty.evtDay}>{new Date(ev.date).getDate()}</Text>
            <Text style={sty.evtMon}>{new Date(ev.date).toLocaleDateString('de-CH',{month:'short'})}</Text>
          </View>
          <View style={sty.evtBody}>
            <Text style={sty.evtTitle} numberOfLines={1}>{ev.title}</Text>
            <Text style={sty.evtMeta}>📍 {ev.location} · 🕐 {ev.time}</Text>
          </View>
          <Text style={[sty.evtPrice, {color: RED}]}>{ev.price}</Text>
        </View>
      ))}

      {/* Suche */}
      <View style={sty.searchBox}>
        <Text style={{fontSize:18, color:RED, marginRight:8}}>⌕</Text>
        <TextInput
          style={sty.searchIn}
          placeholder="Aktivitäten, Restaurants, Hotels…"
          placeholderTextColor={GRAY}
          value={query}
          onChangeText={setQuery}
        />
        {query.length > 0 && (
          <TouchableOpacity onPress={()=>setQuery('')}>
            <Text style={{color:GRAY, fontSize:14}}>✕</Text>
          </TouchableOpacity>
        )}
      </View>

      {/* Kategorien */}
      <ScrollView horizontal showsHorizontalScrollIndicator={false}
        contentContainerStyle={{paddingLeft:16, paddingBottom:10, gap:7}}>
        {CATEGORIES.map(c => {
          const active = cat === c.id;
          const count = c.id === 'all' ? getAllItems(liveListings).length : (activeDB[c.id]||[]).length;
          return (
            <TouchableOpacity key={c.id}
              style={[sty.catBtn, active && {backgroundColor: c.color, borderColor: c.color}]}
              onPress={()=>{ setCat(c.id); setSubFilter('all'); }}>
              <Text style={{fontSize:16}}>{c.icon}</Text>
              <Text style={[sty.catLbl, active && {color:'#fff'}]}>{c.label}</Text>
              <View style={[sty.catCnt, active && {backgroundColor:'rgba(255,255,255,0.25)'}]}>
                <Text style={[{fontSize:9, color:GRAY}, active && {color:'#fff'}]}>{count}</Text>
              </View>
            </TouchableOpacity>
          );
        })}
      </ScrollView>

      {/* Subfilters */}
      {cat !== 'all' && SUBFILTERS[cat] && (
        <ScrollView horizontal showsHorizontalScrollIndicator={false}
          contentContainerStyle={{paddingLeft:16, paddingBottom:10, paddingRight:16}}>
          {SUBFILTERS[cat].map(sf => {
            const col = CATEGORIES.find(c=>c.id===cat)?.color || RED;
            const active = subFilter === sf.id;
            return (
              <TouchableOpacity key={sf.id}
                style={{
                  flexDirection:'row', alignItems:'center', gap:5,
                  paddingHorizontal:14, paddingVertical:7, borderRadius:20,
                  borderWidth:1.5,
                  borderColor: active ? col : LGRAY,
                  backgroundColor: active ? col : WHITE,
                  marginRight:8}}
                onPress={() => setSubFilter(sf.id)}>
                <Text style={{fontSize:13}}>{sf.icon}</Text>
                <Text style={{fontSize:12, fontWeight:'600',
                  color: active ? '#fff' : '#3c3c43'}}>{sf.label}</Text>
              </TouchableOpacity>
            );
          })}
        </ScrollView>
      )}

      {/* Einträge */}
      <View style={sty.sectionHeader}>
        <Text style={sty.sectionTitle}>
          {cat==='all'?'Alle Einträge':CATEGORIES.find(c=>c.id===cat)?.label}
        </Text>
        <Text style={sty.sectionSub}>{filtered.length} Einträge</Text>
      </View>

      <View style={{paddingHorizontal:16, paddingBottom:24}}>
        {filtered.length === 0 && (
          <View style={sty.empty}>
            <Text style={{fontSize:32, marginBottom:8}}>🔍</Text>
            <Text style={{color:GRAY, fontSize:14}}>Keine Einträge gefunden</Text>
          </View>
        )}
        {filtered.map((item, i) => {
          const col = CAT_COLORS[item.category] || RED;
          return (
            <React.Fragment key={item.id}>
              <TouchableOpacity style={sty.listCard} onPress={()=>setDetail(item)}>
                <View style={[sty.listThumb, {backgroundColor: col}]}>
                  <Text style={{fontSize:24}}>{CAT_ICONS[item.category]}</Text>
                  {item.highlight && <Text style={sty.starBadge}>✨</Text>}
                </View>
                <View style={sty.listBody}>
                  <Text style={sty.listName} numberOfLines={1}>{item.name}</Text>
                  {item.address ? <Text style={sty.listAddr} numberOfLines={1}>📍 {item.address}</Text> : null}
                  <View style={sty.chipsRow}>
                    {item.hours ? <View style={sty.chip}><Text style={sty.chipTxt}>🕐 {item.hours.slice(0,20)}{item.hours.length>20?'…':''}</Text></View> : null}
                    {item.cuisine ? <View style={sty.chip}><Text style={sty.chipTxt}>{item.cuisine.split('/')[0].trim()}</Text></View> : null}
                    {item.stars   ? <View style={sty.chip}><Text style={sty.chipTxt}>⭐ {item.stars}</Text></View> : null}
                  </View>
                </View>
                <TouchableOpacity onPress={()=>toggleSave(item.id)} style={sty.heartBtn}>
                  <Text style={{fontSize:22, color: saved.includes(item.id) ? col : LGRAY}}>
                    {saved.includes(item.id) ? '♥' : '♡'}
                  </Text>
                </TouchableOpacity>
              </TouchableOpacity>
              {(i+1)%6===0 && (
                <View style={sty.inAd}>
                  <Text style={sty.inAdTag}>Anzeige</Text>
                  <Text style={sty.inAdTxt}>🏨 Banana City Hotel – ab CHF 149/Nacht</Text>
                </View>
              )}
            </React.Fragment>
          );
        })}
      </View>
    </ScrollView>
  );

  // ── Tab: Kalender ─────────────────────────────────────────────
  const CalendarTab = () => {
    const yr = calMonth.getFullYear(), mo = calMonth.getMonth();
    const evs = ((liveEvents && liveEvents.length > 0) ? liveEvents : EVENTS).filter(e => {
      const d = new Date(e.date);
      return d.getFullYear()===yr && d.getMonth()===mo && (calCat==='all'||e.cat===calCat);
    });
    return (
      <ScrollView style={sty.scroll} showsVerticalScrollIndicator={false}>
        <View style={sty.hero}>
          <View style={sty.heroRow}>
            <Image source={{uri: WAPPEN}} style={{width:34, height:40}} resizeMode="contain"/>
            <View style={{flex:1, marginLeft:12}}>
              <Text style={sty.heroSup}>Veranstaltungen</Text>
              <Text style={sty.heroTitle}>Kalender</Text>
            </View>
          </View>
        </View>

        {/* Monat Nav */}
        <View style={sty.monthNav}>
          <TouchableOpacity style={sty.mBtn}
            onPress={()=>setCalMonth(m=>new Date(m.getFullYear(),m.getMonth()-1,1))}>
            <Text style={{color:RED,fontSize:20,fontWeight:'700'}}>‹</Text>
          </TouchableOpacity>
          <Text style={sty.mLbl}>
            {calMonth.toLocaleDateString('de-CH',{month:'long',year:'numeric'})}
          </Text>
          <TouchableOpacity style={sty.mBtn}
            onPress={()=>setCalMonth(m=>new Date(m.getFullYear(),m.getMonth()+1,1))}>
            <Text style={{color:RED,fontSize:20,fontWeight:'700'}}>›</Text>
          </TouchableOpacity>
        </View>

        {/* Filter */}
        <ScrollView horizontal showsHorizontalScrollIndicator={false}
          contentContainerStyle={{paddingLeft:16, paddingBottom:10, gap:7}}>
          {['all','festival','musik','kultur','markt','theater','tour','kulinarik','sport'].map(c=>{
            const labels={all:'Alle',festival:'Festival',musik:'Musik',kultur:'Kultur',markt:'Märkte',theater:'Theater',tour:'Touren',kulinarik:'Kulinarik',sport:'Sport'};
            const icons={all:'⊞',festival:'🎪',musik:'🎵',kultur:'🎨',markt:'🛍️',theater:'🎭',tour:'🗺️',kulinarik:'🍷',sport:'🏅'};
            const active=calCat===c;
            return (
              <TouchableOpacity key={c}
                style={[sty.catBtn,active&&{backgroundColor:RED,borderColor:RED}]}
                onPress={()=>setCalCat(c)}>
                <Text style={{fontSize:14}}>{icons[c]}</Text>
                <Text style={[sty.catLbl,active&&{color:'#fff'}]}>{labels[c]}</Text>
              </TouchableOpacity>
            );
          })}
        </ScrollView>

        {evs.length===0 && (
          <View style={sty.empty}>
            <Text style={{fontSize:34,marginBottom:10}}>📅</Text>
            <Text style={{color:GRAY,fontSize:14}}>Keine Events in diesem Monat</Text>
          </View>
        )}

        <View style={{paddingHorizontal:16, paddingBottom:24}}>
          {evs.map(ev=>{
            const d=new Date(ev.date);
            return (
              <View key={ev.id} style={sty.evtFullCard}>
                <View style={{flexDirection:'row',alignItems:'flex-start',gap:10,marginBottom:6}}>
                  <View style={[sty.dayCircle,{backgroundColor:RED}]}>
                    <Text style={{color:'#fff',fontSize:15,fontWeight:'800'}}>{d.getDate()}</Text>
                    <Text style={{color:'rgba(255,255,255,0.75)',fontSize:9,textTransform:'uppercase'}}>{d.toLocaleDateString('de-CH',{month:'short'})}</Text>
                  </View>
                  <View style={{flex:1}}>
                    <Text style={sty.evtFullTitle}>{ev.title}</Text>
                    <Text style={sty.evtFullMeta}>📍 {ev.location} · 🕐 {ev.time}</Text>
                  </View>
                  <View style={[sty.priceBadge,{borderColor:RED}]}>
                    <Text style={{color:RED,fontSize:11,fontWeight:'700'}}>{ev.price}</Text>
                  </View>
                </View>
                <Text style={sty.evtFullDesc}>{ev.desc}</Text>
              </View>
            );
          })}
        </View>
      </ScrollView>
    );
  };

  // ── Tab: Saved ────────────────────────────────────────────────
  const SavedTab = () => {
    const savedItems = getAllItems(liveListings).filter(i => saved.includes(i.id));
    return (
      <ScrollView style={sty.scroll} showsVerticalScrollIndicator={false}>
        <View style={sty.hero}>
          <View style={sty.heroRow}>
            <Image source={{uri: WAPPEN}} style={{width:34, height:40}} resizeMode="contain"/>
            <View style={{flex:1,marginLeft:12}}>
              <Text style={sty.heroSup}>Meine</Text>
              <Text style={sty.heroTitle}>Favoriten</Text>
            </View>
          </View>
        </View>
        {savedItems.length===0 ? (
          <View style={sty.empty}>
            <Text style={{fontSize:42,marginBottom:12}}>♡</Text>
            <Text style={{fontWeight:'700',fontSize:16,color:DARK,marginBottom:6}}>Noch leer</Text>
            <Text style={{color:GRAY,fontSize:13}}>Tippe ♡ um Orte zu merken</Text>
          </View>
        ) : (
          <View style={{padding:16}}>
            {savedItems.map(item=>{
              const col=CAT_COLORS[item.category]||RED;
              return (
                <TouchableOpacity key={item.id} style={sty.listCard} onPress={()=>setDetail(item)}>
                  <View style={[sty.listThumb,{backgroundColor:col}]}>
                    <Text style={{fontSize:24}}>{CAT_ICONS[item.category]}</Text>
                  </View>
                  <View style={sty.listBody}>
                    <Text style={sty.listName}>{item.name}</Text>
                    {item.address?<Text style={sty.listAddr}>📍 {item.address}</Text>:null}
                  </View>
                  <TouchableOpacity onPress={()=>toggleSave(item.id)} style={sty.heartBtn}>
                    <Text style={{fontSize:22,color:col}}>♥</Text>
                  </TouchableOpacity>
                </TouchableOpacity>
              );
            })}
          </View>
        )}
      </ScrollView>
    );
  };

  // ── Tab: Karte ────────────────────────────────────────────────
  const MapTab = () => (
    <View style={{flex:1, backgroundColor:BG}}>
      <View style={sty.hero}>
        <View style={sty.heroRow}>
          <Image source={{uri: WAPPEN}} style={{width:34,height:40}} resizeMode="contain"/>
          <View style={{flex:1,marginLeft:12}}>
            <Text style={sty.heroSup}>Interaktiv</Text>
            <Text style={sty.heroTitle}>Karte</Text>
          </View>
        </View>
      </View>
      <View style={{flex:1, alignItems:'center', justifyContent:'center', padding:30}}>
        <Text style={{fontSize:56, marginBottom:16}}>🗺️</Text>
        <Text style={{fontSize:17,fontWeight:'700',color:DARK,marginBottom:8}}>Kartenansicht</Text>
        <Text style={{fontSize:13,color:GRAY,textAlign:'center',lineHeight:20}}>
          Alle {getAllItems(liveListings).length} Einträge als Pins auf Google Maps.{'\n'}
          Installiere react-native-maps für die echte Karte:{'\n\n'}
          npx expo install react-native-maps
        </Text>
      </View>
    </View>
  );

  // ── Detail Modal ──────────────────────────────────────────────
  const DetailSheet = () => {
    if(!detail) return null;
    const col = CAT_COLORS[detail.category] || RED;
    return (
      <Modal visible={true} animationType="slide" transparent onRequestClose={()=>setDetail(null)}>
        <TouchableOpacity style={sty.overlay} activeOpacity={1} onPress={()=>setDetail(null)}/>
        <View style={sty.sheet}>
          <View style={[sty.sheetHead, {backgroundColor: col}]}>
            <Text style={sty.sheetCat}>{CAT_ICONS[detail.category]} {CATEGORIES.find(c=>c.id===detail.category)?.label}</Text>
            <Text style={sty.sheetName}>{detail.name}</Text>
            {detail.address ? <Text style={sty.sheetAddr}>📍 {detail.address}</Text> : null}
            <TouchableOpacity style={sty.sheetClose} onPress={()=>setDetail(null)}>
              <Text style={{color:'#fff',fontSize:16,fontWeight:'700'}}>✕</Text>
            </TouchableOpacity>
          </View>
          <ScrollView style={{padding:16}}>
            {detail.hours   && <InfoRow label="🕐 Öffnungszeiten" val={detail.hours}/>}
            {detail.cuisine && <InfoRow label="🍴 Typ / Küche"    val={detail.cuisine}/>}
            {detail.stars   && <InfoRow label="⭐ Sterne"         val={`${detail.stars} Sterne`}/>}
            {detail.desc    && <InfoRow label="ℹ️ Info"           val={detail.desc}/>}
            {detail.phone   && <InfoRow label="📞 Telefon"        val={detail.phone} color={col}/>}
            <TouchableOpacity
              style={[sty.saveSheetBtn, {backgroundColor: saved.includes(detail.id)?col:'transparent', borderColor:col}]}
              onPress={()=>toggleSave(detail.id)}>
              <Text style={{color: saved.includes(detail.id)?'#fff':col, fontWeight:'700', fontSize:15}}>
                {saved.includes(detail.id)?'♥  Gespeichert':'♡  Merken'}
              </Text>
            </TouchableOpacity>
          </ScrollView>
        </View>
      </Modal>
    );
  };

  const InfoRow = ({label, val, color}) => (
    <View style={sty.infoRow}>
      <Text style={sty.infoLabel}>{label}</Text>
      <Text style={[sty.infoVal, color && {color}]}>{val}</Text>
    </View>
  );

  // ── Bottom Tabs ───────────────────────────────────────────────
  const TABS = [
    {id:'home',     icon:'⊞', label:'Entdecken'},
    {id:'calendar', icon:'📅',label:'Kalender'},
    {id:'map',      icon:'◎', label:'Karte'},
    {id:'saved',    icon:'♡', label:'Favoriten'},
  ];

  return (
    <SafeAreaView style={sty.container} edges={['top']}>
      <StatusBar barStyle="light-content" backgroundColor={RED2}/>

      <View style={{flex:1}}>
        {tab==='home'     && <HomeTab/>}
        {tab==='calendar' && <CalendarTab/>}
        {tab==='map'      && <MapTab/>}
        {tab==='saved'    && <SavedTab/>}
      </View>

      {/* Bottom Navigation */}
      <View style={sty.bottomNav}>
        {TABS.map(t => (
          <TouchableOpacity key={t.id} style={sty.navItem} onPress={()=>setTab(t.id)}>
            <Text style={[sty.navIcon, tab===t.id && {color: RED}]}>{t.icon}</Text>
            <Text style={[sty.navLabel, tab===t.id && {color: RED, fontWeight:'700'}]}>{t.label}</Text>
            {tab===t.id && <View style={sty.navDot}/>}
          </TouchableOpacity>
        ))}
      </View>

      <DetailSheet/>
    </SafeAreaView>
  );
}

