  hlAddr:       {fontSize:10, color:GRAY},

  // Events preview
  evtRow:       {flexDirection:'row', alignItems:'center', marginHorizontal:16, marginBottom:8, backgroundColor:WHITE, borderRadius:12, overflow:'hidden', shadowColor:'#000', shadowOffset:{width:0,height:1}, shadowOpacity:0.05, shadowRadius:4, elevation:2},
  evtDate:      {width:44, paddingVertical:10, alignItems:'center', justifyContent:'center'},
  evtDay:       {color:'#fff', fontSize:18, fontWeight:'800', lineHeight:20},
  evtMon:       {color:'rgba(255,255,255,0.75)', fontSize:10, textTransform:'uppercase'},
  evtBody:      {flex:1, paddingVertical:10, paddingHorizontal:10},
  evtTitle:     {fontSize:13, fontWeight:'700', color:DARK, marginBottom:2},
  evtMeta:      {fontSize:11, color:GRAY},
  evtPrice:     {fontSize:11, fontWeight:'700', paddingRight:12},

  // Search
  searchBox:    {marginHorizontal:16, marginTop:10, marginBottom:6, backgroundColor:WHITE, borderRadius:12, flexDirection:'row', alignItems:'center', paddingHorizontal:14, paddingVertical:10, shadowColor:'#000', shadowOffset:{width:0,height:1}, shadowOpacity:0.05, shadowRadius:4, elevation:2},
  searchIn:     {flex:1, fontSize:14, color:DARK},

  // Categories
  catBtn:       {alignItems:'center', gap:3, paddingHorizontal:12, paddingVertical:8, borderRadius:12, borderWidth:1.5, borderColor:LGRAY, backgroundColor:WHITE},
  catLbl:       {fontSize:9, fontWeight:'600', color:'#3c3c43'},
  catCnt:       {backgroundColor:VLGRAY, borderRadius:20, paddingHorizontal:6, paddingVertical:1},

  // List cards
  listCard:     {flexDirection:'row', backgroundColor:WHITE, borderRadius:14, overflow:'hidden', marginBottom:8, shadowColor:'#000', shadowOffset:{width:0,height:1}, shadowOpacity:0.05, shadowRadius:4, elevation:2},
  listThumb:    {width:72, alignItems:'center', justifyContent:'center', position:'relative'},
  starBadge:    {position:'absolute', top:4, right:4, fontSize:11},
  listBody:     {flex:1, padding:11},
  listName:     {fontSize:14, fontWeight:'700', color:DARK, marginBottom:2},
  listAddr:     {fontSize:11, color:GRAY, marginBottom:5},
  chipsRow:     {flexDirection:'row', flexWrap:'wrap', gap:4},
  chip:         {backgroundColor:VLGRAY, borderRadius:20, paddingHorizontal:8, paddingVertical:2},
  chipTxt:      {fontSize:10, color:'#3c3c43'},
  heartBtn:     {paddingHorizontal:14, alignSelf:'center'},
  inAd:         {flexDirection:'row', alignItems:'center', gap:8, backgroundColor:'rgba(0,0,0,0.03)', borderRadius:10, padding:10, marginBottom:8},
  inAdTag:      {fontSize:8, letterSpacing:1.2, textTransform:'uppercase', color:'#bbb'},
  inAdTxt:      {fontSize:11, color:'#6b6b6b'},
