  // Calendar
  monthNav:     {flexDirection:'row', alignItems:'center', justifyContent:'space-between', padding:12, paddingHorizontal:20, backgroundColor:WHITE, borderBottomWidth:1, borderBottomColor:LGRAY},
  mBtn:         {width:36, height:36, borderRadius:8, borderWidth:1.5, borderColor:LGRAY, alignItems:'center', justifyContent:'center'},
  mLbl:         {fontSize:15, fontWeight:'700', color:DARK},
  evtFullCard:  {backgroundColor:WHITE, borderRadius:14, padding:14, marginBottom:10, shadowColor:'#000', shadowOffset:{width:0,height:1}, shadowOpacity:0.05, shadowRadius:4, elevation:2},
  dayCircle:    {width:40, height:40, borderRadius:20, alignItems:'center', justifyContent:'center'},
  evtFullTitle: {fontSize:14, fontWeight:'700', color:DARK, marginBottom:2},
  evtFullMeta:  {fontSize:11, color:GRAY, marginBottom:6},
  evtFullDesc:  {fontSize:12, color:'#6b6b6b', lineHeight:18},
  priceBadge:   {borderWidth:1.5, borderRadius:20, paddingHorizontal:9, paddingVertical:2, alignSelf:'flex-start'},

  // Modal/Sheet
